local my_lua_table = {
	["green_book_lindon"] = {
		name = 'Lindon',
		desc = 'Lindon (Land of Song) is a wide land in the Northwest of Middle-earth that is subdivided into two areas: Forlindon (North Lindon) and Harlindon (South Lindon). The great Gulf of Lhûn seperates the two subdivisions and houses, at its conflux with the Lhûn river, the famous city of Mithlond (Grey Haven). Prior to the fall of Beleriand, the western part of Lindon was known as Ossiriand (Land of Seven Rivers) and Lindon as a name was rarely used. Lindon as a royal realm (called the Kingdom of Lindon) was founded at the start of the Second Age by Gil-galad, the last High King of the Noldor-in-Exile. His people were those Elves fleeing the destruction of Beleriand. The Kingdom of Lindon has endured since that time through many wars and much strife but now dwindles as the Elves use Mithlond as the departure point for all of Middle-earth.\\n\\nTerrain:\\nGrey Havens - Grassland\\nForlindon - Forest\\nHarlindon - Forest\\nWestern Numeriador - Forest',
		desc_short = 'Lindon',
	},
	["green_book_shire"] = {
		name = 'The Shire',
		desc = 'The Shire is the region occupied by Hobbits and is located in the north-west of Middle-earth. It is a small but beautiful and fruitful land, beloved by its inhabitants. The Hobbits have an extensive agricultural system in the Shire, but do not proceed with industrialization. Various supplies can be found in the Shire, including cereals, fruit, wood and pipe-weed (a favourite treat of Hobbits). The Shire is quite densely populated in parts with many villages and a few towns, but it still is open enough to allow for wide forested areas and marshes. The Shire is a simple place and large constructs are of no interest to the Hobbits, as such Michel Delving will never be anything more than a simple wooden walled town whilst Longbottom and Hobbiton will remain villages indefinitely.\\n\\nTerrain:\\nShire (West) - Grassland\\nShire (North) - Grassland\\nShire (South) - Grassland\\nEmyn Beraid - Mountainous',
		desc_short = 'The Shire',
	},
	["green_book_arthedain"] = {
		name = 'Arthedain',
		desc = 'Arthedain is one of the three kingdoms of Middle-earth that resulted from the breakup of Arnor during the Third Age.\\nIn T.A. 1601, Hobbits came to Arthedain. With permission of Argeleb II, they settled in the land that would later be called "the Shire". They would be subject to the Kings of Arthedain, and tasked with maintenance to infrastructure, especially of the vital Bridge of Stonebows. Arthedain endured the longest of all the Dúnedain successor states but eventually fell on T.A. 1974 after the Witch-king captured Fornost. However, a year later, an army lead by Eärnur of Gondor landed in Lindon and after allying with the Elves there, he and Glorfindel engineered a great victory over the evil of the north and totally crushed the realm of Angmar. It was in this decisive battle that Glorfindel prophesized that \'not by the hand of man would the Witch-king fall\'. His prophecy came true 1045 years later on the Pelennor Fields of Gondor.\\n\\nTerrain:\\nEastern Numeriador - Grassland\\nLake Evendim - Mountainous\\nNorth Downs - Grassland\\nArthedain Fields - Grassland\\nBorder Lands - Grassland\\nEvendim - Mountainous',
		desc_short = 'Arthedain',
	},
	["green_book_Angmar"] = {
		name = 'Angmar',
		desc = 'The land of Angmar is a vast plain stretching from the two arms of the Misty Mountains out to the borders of the bay of Forochel. It is a barren, rocky expanse that is unsuitable for agriculture, and is in practice a cold desert. The vast majority of the population inhabits the great valley between Mount Gram and the last spur of the Misty Mountains leading to Carn Dûm. Here there are some sheltered vales and farming can be attempted. Wolves roam the foothills of the mountains, finding food wherever they can and most settlements are built on the strategic sites of old iron mines that predate the Witch-king’s rule.\\n\\nTerrain:\\nDordholl - Forest\\nUdanoriath - Grassland\\nRhachang - Barren',
		desc_short = 'Angmar',
	},
	["green_book_forochel"] = {
		name = 'Forochel',
		desc = "Forochel had been made very cold earlier in Arda's history because of the presence of Utumno and Morgoth's evil cold emanating from it. The region remained cold even after Utumno's destruction. The only known inhabitants of this frozen wasteland are the Lossoth of Forochel on the very western edge of Fordwaith. They were a simple people who fished to survive and rarely came into contact with the rest of the world. The only notable interaction was when the last king of Arnor, Arvedui, sought refuge and aid from the Lossoth after Angmar's power became to great for Arthedain to hold back. He asked only for a boat so that he and his line could escape with the palantir of the north, the Lossoth helped him but he was lost in the ice-bay along with the Palantir. The frozen lands here are so unforgiving that only small communities can survive as too many people requires too much food, as such nothing more than small palisaded towns can exist here.\\n\\nTerrain:\\nOiolad - Barren\\nTalath Muil - Barren",
		desc_short = 'Forochel',
	},
	["green_book_Rhudaur"] = {
		name = 'Rhudaur',
		desc = "In Sindarin, Rhudaur translates to “Eastern Forests” and was so named owing to the vast stretches of woodland that dominated this region when the Númenóreans first settled in Eriador. The region of Rhudaur was the smallest of the successor states of Arnor, and the first to be corrupted by the influence of the Witch-king of Angmar. In secret, evil chieftains allied themselves with Angmar and began to rally many of the poor and filthy hillmen to their cause. They aroused the hatred these men felt for the proud and rich 'pure blooded' Númenóreans of Arthedain and Cardolan. These puppet chieftains governed Rhudaur from the far north, but their influence had difficulty spreading southward due to the influence of the Elves of Imladris. The hillmen had no major cities and the Dúnedain only built castles along the banks of the Hoarwell leaving many Rhudaurians to live in huts, tents and small villages. The evil of Angmar used this to their advantage and as such those who did not side with the Witch-king were easily caste out or cut down. After the fall of Angmar in T.A 1975, the population of Rhudaur dwindled owing primarily to the coming of Hill-trolls from the Ettenmoors. the land was slowly forgotten as 'Rhudaur' and came to be known as the Trollshaws and a bloody black and forth between the Dúnedain and the Trolls dominated the area's history for the remainder of the Third Age. Some hillmen endured and ontinue to live here however: almost forgotten to history.\\n\\nTerrain:\\nRhudaur Uplands - Forest\\nRhudaur Lowlands - Grassland",
		desc_short = 'Rhudaur',
	},
	["green_book_ettenmoors"] = {
		name = 'Ettenmoors',
		desc = 'The Ettenmoors lie to the north of old Rhudaur and have long been wild and untamed. Hill-trolls have lived here since before the days of Arnor and Angmar and gave the their name to the region. The area is formed of wide grasslands, broken with jagged rock and small thickets. Rain lashes the slopes of the Ettenmoors daily and a thick fog often covers the ground when the rain subsides. It is not a friendly or welcoming place and only the hardy Hillmen and small pockets of Dúnedain call the land home. The Hill-trolls and the Dúnedain have long battled in the region with Arathorn II as the latest famous victim.\\n\\nTerrain:\\nEttenmoors - Mountainous',
		desc_short = 'Ettenmoors',
	},
	["green_book_Angle"] = {
		name = 'En Egladil',
		desc = 'En Egladil or “The Angle” is the thin spit of land formed by the convergence of the rivers Mitheithel and Bruinen and the former population centre of the Kingdom of Rhudaur. Since the collapse of civilization in Eriador, the Angle has been a site of constant struggle between Hill-trolls and Eriadoran commoners, the latter aided by the Rangers of the North, who are among the last inhabitants of this area at the close of the Third Age. This region came to be the new home of the Dúnedain after the fall of Arnor as it had natural defences and could call on Imladris for aid if the situation grew dire.\\n\\nTerrain:\\nThe Angle - Forest',
		desc_short = 'En Egladil',
	},
	["green_book_Imladris"] = {
		name = 'Hidden Valley',
		desc = 'The Hidden Valley is the name given to the vast fertile canyon that sits perpendicular to the run of the Misty Mountains in eastern Eriador. At this great valley\'s centre sits the famed home of Elrond Half-elven: Rivendell (Imladris). Rivendell is known as "The Last Homely House East of the Sea", a reference to it being the boundary of the \'peaceful\' lands of Eriador (lands, in the late Third Age, that are free of Sauron\'s influence). It was established by Elrond in the S.A 1697 as a refuge from Sauron after the fall of Eregion. After the victory of the Last Alliance and the death of Gil-galad, Imladris became the chief dwelling of the remaining High Elves although many still resided in Lindon. Imladris is also an important settlement to the Dúnedain as it houses the shards of Narsil and gave refuge to the Dúnedain chieftains after the fall of Arnor. Besides Elrond, Imladris is also home to Arwen, Elladan, Elrohir, Erestor and Glorfindel.\\n\\nTerrain:\\nHidden Valley - Mountainous',
		desc_short = 'Hidden Valley',
	},
	["green_book_cardolan"] = {
		name = 'Cardolan',
		desc = 'Cardolan is a breakaway realm of the Dúnedain kingdom of Arnor. After the death of its tenth King, Eärendur, his sons divided the kingdom into the kingdoms of Arthedain, Rhudaur and Cardolan. Cardolan stretches from the river Baranduin to the Mitheithel. Its northern border is the Great East Road, but Cardolan also claims the Weather Hills, which contain the fortress of Amon Sûl. Amon Sûl housed a Palantir, and for this reason it was also claimed by Rhudaur. This lead to a bitter conflict which continued until Rhudaur became a vassal of Angmar after the line of the Dúnedain failed there. After the final fall of Arnor, and the destruction of Angmar at the Battle of Fornost, Cardolan remained an almost unpopulated area. Cardolan was conquered in T.A. 1409 by the forces of Angmar: rather than besiege the Cardolanians major encampment atop the Barrow-downs, the twisted forces of Angmar sent evil spirits to occupy the barrows and this forced the armies of Cardolan to leave their defensive position, allowing them to be destroyed. Despite the deserted land, the Greenway still runs through the region and is used by travellers, albeit infrequently. Additionally many petty Kingdoms split off from the remnants of the realm, such as the Kingdom of Saralainn.\\n\\nTerrain:\\nEgenyar - Grassland\\nCardolan Proper - Forest\\nSwanfleet - Barren\\nFaerdor - Grassland\\nLone-lands - Grassland',
		desc_short = 'Cardolan',
	},
	["green_book_Bree"] = {
		name = 'Bree',
		desc = 'Bree is settled in the realm Cardolan and though the Princes of Cardolan claimed it, Bree continued to thrive without any central authority or government for many centuries.\\nBree is by its nature a trading community, due to being located at the major crossroads of the Great East Road which runs from the Blue Mountains and the coast to Dale in the far East, and the old north-south road between Arnor and Gondor. The latter had fallen out of much use since the destruction of Arnor, and is more commonly referred to as the Greenway due to its disrepair.\\n\\nTerrain:\\nBree-land - Forest',
		desc_short = 'Bree',
	},
	["green_book_Minhiriath"] = {
		name = 'Minhiriath',
		desc = "Minhiriath (Sindarin: 'Between Rivers') is a wide gentle land that made up the southern reaches of both Arnor and Cardolan after it. It is an unremarkeable land with few inhabitants and even fewer landmarks. Its northern border is bounded by the Brandywine river and its southern - the Gwathló. The forests of Minhiriath, such as Eryn Vorn, were overfarmed by the Númenóreans leaving empty grassland in their wake. The land was then devastated by Sauron in the Second Age and by the Witch-king in the Third. Fishermen do still inhabit the waterways of Minhiriath but the interior is a grass desert.\\n\\nTerrain:\\nGirithlin - Grassland\\nCaladir - Forest\\nSaralainn - Grassland\\nNêlchelyn - Mountainous",
		desc_short = 'Minhiriath',
	},
	["green_book_Eregion"] = {
		name = 'Eregion',
		desc = "Eregion or Hollin was a kingdom of the Ñoldor Elves in Eriador during the Second Age, located near the West Gate of Khazad-dûm under the shadow of the Hithaeglir (Misty Mountains). Its capital was Ost-in-Edhil.After Galadriel and Celeborn had left, Eregion was ruled by Celebrimbor, a descendant of Fëanor. Under his rule the Elves of Eregion became friends with Annatar, Lord of Gifts, and created the Rings of Power. When Annatar was revealed as the Dark Lord Sauron the Elves of Eregion tried to keep the Rings from falling in Sauron's hands, but only managed to rescue Vilya, Narya, and Nenya (the Three Rings of the Elves). Eregion was utterly destroyed, and its survivors fled to Lindon, Lothlórien, and the refuge of Imladris (Rivendell). In the Third Age, Eregion is a pleasant but unpopulated land.\\n\\nTerrain:\\nEregion - Grassland\\nHollin - Mountainous\\nLoudwater Fields - Grassland",
		desc_short = 'Eregion',
	},
	["green_book_Dunland"] = {
		name = 'Dunland',
		desc = "Dunland means 'Hill Land' in the language of neighbouring Rohan, who's people named it after arriving in nearby Calenardhon in the later Third Age.\\nThe ancient ancestors of the Dunlendings inhabited the forested regions of Middle-earth either side of the Gwathló in the early Second Age, and so were called 'Gwaithuirim' by the early Númenóreans. They spoke a language related to that of the Second House of Men, the Haladin, rather than the vastly different Bëorian/Marachian tongue which stood at the base of Adûnaic, and this lack of mutual understanding led to outright hostility. The Númenóreans greedily harvested their forests for timber, and after much war and bloodshed, the Gwaithuirim from south of the Gwathlo fled east to the Hithaeglir, while others scattered to the cape of Eryn Vorn and the White Mountains.\\n\\nTerrain:\\nDunland Lowlands - Grassland\\nDunland Border - Grassland\\n Dunland Proper - Mountainous",
		desc_short = 'Dunland',
	},
	["green_book_Enedwaith"] = {
		name = 'Enedwaith',
		desc = 'Enedwaith originally refers to both a region of Middle-earth and the men that inhabited it, although the region Enedwaith retained that name even when the Enedwaith people were no more. During the First and early Second Age Enedwaith was deeply forested, but the arrival of the timber-hungry Númenóreans, from the seventh century of the Second Age onwards, devastated the landscape. The denuded forests of Enedwaith, and much of those to the north in Eriador, were finally destroyed by the War of the Elves and Sauron around S.A. 1700, during which much of what had survived the felling was burnt. Only remote corners like Eryn Vorn survived in Eriador, and the Old Forest still further north. Many surviving natives took refuge in the eastern highlands of Enedwaith, "the foothills of the Misty Mountains", which ultimately became Dunland. Life is hard within this simple land and stone is a rare commodity, as such the towns of Bregnas and Carras are unable to grow far beyond large towns.\\n\\nTerrain:\\nLarfearann - Grassland\\nCairill - Forest\\nMaolfinn - Forest\\nLugiu - Forest\\nHeorotscir - Mountainous\\nFortriu - Grassland\\nAdorn Vale - Grassland\\nMaolrunaidh - Forest\\nWestern Enedwaith - Forest',
		desc_short = 'Enedwaith',
	},
	["green_book_Dale"] = {
		name = 'Dale',
		desc = 'Dale is a city of the Northmen, situated between Erebor and Esgaroth. It was founded by the Northmen who lived near Erebor, probably to benefit from trade with the Dwarves in Erebor, who were seen as an ally. Dale was destroyed when Smaug descended on the Dwarf-kingdom of Erebor and for one-hundred and seventy-two years the city lay in ruins. After the Battle of Five Armies Dale was rebuilt by Bard the Bowman, the descendant of its royal line.\\n\\nTerrain:\\nRealm of Dale - Grassland\\nPlains of Arafel - Grassland\\nGramavuld - Grassland\\nCarnen Fields - Grassland',
		desc_short = 'Dale',
	},
	["green_book_Erebor"] = {
		name = 'Erebor',
		desc = 'Erebor, or the Lonely Mountain (which it translates as from Sindarin), is a mountain in the north-east of Rhovanion. It is the source of the river Running, and a major Dwarven stronghold. Erebor was first discovered and colonized by the Longbeards sometime after Durin I awoke in Mount Gundabad. It was inhabited by a mining colony for thousands of years, and was connected by the Forest Road.\\n\\nTerrain:\\nRealm of Erebor - Mountainous',
		desc_short = 'Erebor',
	},
	["green_book_Esgaroth"] = {
		name = 'Esgaroth',
		desc = 'Esgaroth upon the Long Lake, also known as Lake-town, is the township of the Lake-men in Wilderland. The town is constructed entirely of wood and stands upon wooden pillars sunk into the bed of the Long Lake, as a protection against the dragon Smaug, who dwelt nearby in the Lonely Mountain. It is situated on the west side of the lake, north of the mouth of the Forest River in a calm bay that is formed by the shelter of a rock promontory. A long wooden bridge connects the town to the land, ending in a building, with guards watching over the entrance. In the middle of Esgaroth the central market-place is located, which is a round pool connected to the lake by a tunnel. The greatest houses of Esgaroth are around this market-place, from which ramps descend to the water. The edge of the town is occupied with quays and, again, ramps, which descended to the water.\\n\\nTerrain:\\nLong Lake - Grassland',
		desc_short = 'Esgaroth',
	},
	["green_book_Logathavuld"] = {
		name = 'Logathavuld',
		desc = "The hills of Logathavuld span great distances, and serve as a natural barrier to those who wish to enter the far off lands of Rhûn. The north-western hills were occupied by Northmen in the later Second Age, while a small village of men from Rhûn was established in the southern hills. The far east of Logathavuld is rumoured to be protected by a long line of forts and patrols. The foothills of the far off Orocarni find their origin amongst the hills of Logathavuld.\\n\\nTerrain:\\nLogathavuld - Grassland\\nGazar Ueal - Grassland\\nErland's Ferry - Mountainous\\nGazar Barak - Grassland\\nGazar Narkad - Grassland",
		desc_short = 'Logathavuld',
	},
	["green_book_rhun"] = {
		name = 'Rhûn',
		desc = 'Rhûn refers to the little-known lands to the east of Middle-earth inhabited by peoples known as the "Easterlings", from whom many attacks on Gondor and its allies came during the Third Age. Rhûn is the domain of the Easterlings, Men of Darkness who are ready to follow both the Dark Lords and fought as their allies in war. These lands, too, were peopled by lost Elves, Avari and Úmanyar, and by four of the seven clans of the Dwarves who dwelt in the Orocarni. It contains the great Sea of Rhûn, connected with three rivers, one north-east, a part of River Running, one north-west and one running south to Mordor. north-west of the Sea of Rhûn lies the land of Dorwinion. The inland Sea of Rhûn is located in western Rhûn on the border between Rhûn and Wilderland. There are mountains on the south-west side of the Sea of Rhûn and a forest on the north-east side. Wild white Kine of Araw, or oxen, lived near the shores of the Sea of Rhûn.\\n\\nTerrain:\\nSteppes of the Wainriders - Barren\\nRhûnnic Plains - Mountainous\\nRhûnnic Borderlands - Grassland',
		desc_short = 'Rhûn',
	},
	["green_book_Dorwinion"] = {
		name = 'Dorwinion',
		desc = "Dorwinion or Dor-Winion is a land which lay on the north-western shores of the Sea of Rhûn. It is famous for its wine, its warm and temperate climate and for nothing else! Doriwnion is one of the most mysterious locations in Middle-earth for its customs, its people, its architecture and its widlife are all unknown to us. There is suggestion that Dorwinion may be home to a contingent of Avari Elves but this is conjecture. Despite the close etymological connection between 'wine' and 'winion', Dorwinion actually means 'Land of Gwinion' in Sindarin where Gwinion itself means 'young land'.\\n\\nTerrain:\\nDorwinion - Grassland\\nWestern Dorwinion - Grassland",
		desc_short = 'Dorwinion',
	},
	["green_book_Rhovanion"] = {
		name = 'Rhovanion',
		desc = "Rhovanion or Wilderland is a large region of northern Middle-earth. The Great River Anduin flows through it, and the immense forest of Greenwood the Great is a part of it. Properly speaking Rhovanion is the name of a small region east of Greenwood, which later was the Kingdom of Rhovanion, but the name was used for all of Wilderland by the late Third Age. The Kingdom of Rhovanion was founded before the year 490 of the Third Age by a group of Northmen who were led by a 'Prince of Rhovanion'. In Third Age 1636 the Great Plague devastated Rhovanion, killing more than half its people. This left Rhovanion weakened, and in Third Age 1851 the Wainriders overran and enslaved Rhovanion. For 43 years Rhovanion was enslaved, but in Third Age 1899 Rhovanion revolted, while Gondor attacked the Wainriders from the west. Rhovanion was freed, but left extremely weakened. Many Men of Rhovanion left for Gondor, where they were welcomed as distant relatives.\\nAround 2510 a new group of Easterlings, the Balchoth, appeared, and they quickly took the old lands of Rhovanion. This was the final end of Rhovanion as an independent realm.\\n\\nTerrain:\\nPlains of Vidugavia - Forest\\nLeofric's Bowing - Grassland\\nMarches of the Northmen - Grassland\\nEast Bight - Barren\\nBurnt Lands - Grassland\\nLôthaur - Grassland\\nRhuvan - Forest\\nPlains of Sorrow - Mountainous\\nOld Rhûn Road - Grassland\\nWindan Forest - Forest\\nMirvan - Grassland",
		desc_short = 'Rhovanion',
	},
	["green_book_Mirkwood"] = {
		name = 'Mirkwood',
		desc = "Mirkwood or the Forest of Great Fear is a great forest in Rhovanion. It is roughly rectangular in shape: stretching from the foothills of the Grey Mountains in the north to the North Undeep in the south, and from the east edge of the vale of Anduin to Erebor. It is bisected by the ancient Old Forest Road. Later, when this road became unusable, a second path through the forest was made to the north. Between the two paths lie the Mountains of Mirkwood. The Forest River cuts through the forest's northern end from its source in the western Grey Mountains, joins in the centre by the Enchanted River which flows north from the Mountains of Mirkwood. South of the Old Forest road, the East Bight creates the Narrows of the Forest, only one hundred miles across. South and west of the narrows is the hill called Amon Lanc with its fortress, Dol Guldur. \\n\\nTerrain:\\nElven Acres - Forest\\nWoodland Realm - Forest\\nMountains of Mirkwood - Mountainous\\nOld Forest Road - Forest\\nWestern Mirkwood - Forest\\nCentral Mirkwood - Forest\\nEastern Mirkwood - Forest\\nNarrows of Mirkwood - Forest\\nReaches of Mirkwood - Forest",
		desc_short = 'Mirkwood',
	},
	["green_book_Lothlorien"] = {
		name = 'Lothlórien',
		desc = 'Lothlórien is a kingdom of Silvan Elves on the eastern side of the Hithaeglir. It is considered one of the most beautiful and "Elvish" places in Middle-earth during the Third Age, and had the only Mallorn-trees east of the sea. The first inhabitants of the forested area later known as Lórien were a group of Nandor that refused to cross the Hithaeglir. Lórien was probably one of their scattered settlements in the area.\\n\\nTerrain:\\nLothlórien - Forest',
		desc_short = 'Lothlórien',
	},
	["green_book_rohan"] = {
		name = 'Rohan',
		desc = "Rohan's first capital was at Aldburg in the Folde, until King Eorl the Young's son, Brego, built Edoras. It is Rohan's only major city with most of its people dwelling in small towns or villages out on the plains. Beside the King's Land, Rohan is divided into 4 great stretches of land: the Westfold, the Eastfold, West Emnet and East Emnet. Rohan also lays claim to the Westmarch around the river Adorn but this claim is loose and the people here are governed autonomously in truth. Rohan, as a nation, is one of Middle-earth's youngest having only been founded some 500 years ago.\\n\\nTerrain:\\nKings Land - Grassland\\nEastfold - Grassland\\nEast Emnet - Grassland\\nWest Emet - Grassland\\nWestfold - Grassland\\nHelm's Deep - Mountainous\\nGap of Rohan - Grassland\\nFords of Isen - Grassland",
		desc_short = 'Rohan',
	},
	["green_book_Wold"] = {
		name = 'The Wold',
		desc = 'The Wold is the northernmost and least populated part of Rohan, lying between Fangorn Forest and the Anduin, and bordered to the north by the Limlight. Its main feature is a large range of hills, which is split by the River Anduin. The banks of the Anduin in the Wold are lined with reeds but beyond, the region is flat and featureless. The main inhabitants are nomadic Men of Rohan who use the land to graze cattle.\\n\\nTerrain:\\nThe Wold - Barren',
		desc_short = 'The Wold',
	},
	["green_book_Mordor"] = {
		name = 'Mordor',
		desc = 'Mordor is the dwelling place of Sauron, in the south-east of Middle-earth to the East of Anduin, the great river. It is protected from three sides by mountain ranges, arranged roughly rectangular: Ered Lithui in the north, Ephel Dúath in the west, and an unnamed (or possibly still called Ephel Dúath) range in the south. A narrow pass leads through Ephel Dúath and the fortress of Minas Morgul guards it. Due to the vast ashy wastes, harsh conditions and the need for food for inhabitants the watchtowers of Seregost, Morigost, Thaurband and Yrch Estolad are unlikely to expand any further.\\n\\nTerrain:\\nPlains of Orodruin - Barren\\nMorgai Flats - Barren\\nUdûn - Mountainous\\nMorgai Gorge - Mountainous\\nPass of Ungol - Mountainous\\nPlateau of Gorgoroth - Barren',
		desc_short = 'Mordor',
	},
	["green_book_nurn"] = {
		name = 'Nurn',
		desc = "Núrn was a region located in the southernmost portion of the realm of Mordor that held the inland Sea of Núrnen. \\n\\nNúrn was a semi-arid place due to its close proximity to Gorgoroth and consisted mostly of short grass landed plains, fertile enough for farming to support the armies of Sauron, as opposed to the arid plateau of Gorgoroth, which is north-west of Núrn. Núrn was partially inhabited by Westron-speaking men that were enslaved by the Dark Lord Sauron. It was fertile enough to feed Sauron's numberless hordes during the War of the Ring, and covered in vast fields of grain worked by slaves. Its soil had been enriched by ash from Orodruin's eruptions, and its grasslands were fed by water from the Sea of Núrnen. \\n\\nTerrain:\\nPlain of Lithlad - Barren\\nNurn - Grassland",
		desc_short = 'Nurn',
	},
	["green_book_Haradwaith"] = {
		name = 'Haradwaith',
		desc = "Harad is the name of the immense lands to the South of Gondor and Mordor. It is inhabited by many different tribes called Haradrim.\\nThe Mountains of Shadow are on the northern border of Harad. The River Harnen flows westward from the Mountains of Shadow to the Bay of Belfalas, forming Harad's border with South Gondor - a desert region that is contested between Gondor and Harad. The Harad Road runs from Harad northward through South Gondor and on to Ithilien.\\nTo the northeast of Harad is Khand, a land that also has ties with Sauron. On the west, Harad is bounded by the Bay of Belfalas and the Sea.\\nThe northernmost part of Harad is called Near Harad and the southern part is known as Far Harad. On the coast there is a natural harbor with a narrow cape curving around it. The coastal region around the harbor is known as Umbar, and the harbor is called the Havens of Umbar. The seafaring raiders known as the Corsairs live there. At the eastern end of the harbor is the City of the Corsairs.\\nMuch of Far Harad is a jungle, although there also is a desert. In the Great Forest of the South in Far Harad live the gigantic Oliphaunts, which are used by the Haradrim as moving war towers.\\nHarad's location in the far south isolates it to a certain extent from the rest of Middle-earth. The climate is much warmer and sunnier. Even the constellations in Harad's night sky down in the southern hemisphere are different from those in northern Middle-earth.\\n\\nTerrain:\\nLurmsakûn - Barren\\nHaradrim Wastes - Barren\\nPezarsan - Barren\\nFar Chelkar - Barren\\nKajbah - Barren\\nUpper Kajbah - Barren\\nHaruzan - Barren\\nShafra - Barren",
		desc_short = 'Haradwaith',
	},
	["green_book_Umbar"] = {
		name = 'Umbar',
		desc = 'Umbar is one of the trading ports at the southern coast of Middle-earth, which became a base from which Númenórean influence spread over Middle-earth. In S.A. 2280 it was made into a great fortress as a reaction to the growing threat of Sauron and became the strongest and most important. After the Downfall of Númenor, Umbar remained in the hands of the Númenóreans, in essence a realm-in-exile alongside Arnor and Gondor. But unlike these others, Umbar had been used by the Black Númenóreans, who were not friendly to the Elves or to their fellow Faithful Númenórean survivors. Umbar and the southern provinces experienced a rebellion during the civil war of Gondor.\\n\\nTerrain:\\nHaven Lands of Umbar - Barren\\nVinya Mittalmar - Barren\\nVinya Forostar - Barren',
		desc_short = 'Umbar',
	},
	["green_book_Khand"] = {
		name = 'Khand',
		desc = 'Khand is the name of a land which lies to the south-east of Mordor and to the east of Near Harad. The Men of Khand are called Variags. Little is known about Khand or its people, but it appears to be much like Rohan. Due to the harsh conditions and nomadic nature of the peoples here, the settlements of these lands are unlikely to be anything more than large towns.\\n\\nTerrain:\\nGap of Khand - Barren\\nKhand - Barren\\nSprings of Khand - Barren\\nWestern Khand - Barren',
		desc_short = 'Khand',
	},
	["green_book_osgiliath"] = {
		name = 'Osgiliath',
		desc = "Osgiliath was the old capital city of Gondor. The city straddled the Anduin River at a point approximately half way between the cities of Minas Anor to the south-west and Minas Ithil to the north-east, and north of the nearby Emyn Arnen. In its days of glory, the city featured quays to handle sea-going vessels that came up from the sea, a great stone bridge supporting houses and towers of stone, and the Dome of Stars, which housed the Osgiliath-stone, the greatest of the seven Palantíri. The beginning of the city's decline came in T.A. 1437 when it was sacked and burned, after a siege by the rebel Castamir's forces during the Kin-strife. It was during this siege that the Osgiliath-stone was lost in the River. The Great Plague of T.A. 1636 led to further depopulation, and the city began to fall into ruin.\\n\\nTerrain:\\nForests of Ithilien - Forest\\nOsgiliath - Grassland",
		desc_short = 'Osgiliath',
	},
	["green_book_anorien"] = {
		name = 'The Pelennor Fields',
		desc = 'The Pelennor Fields are the enclosed town-lands of south-eastern Anórien, and provide food for the city of Minas Tirith of which it forms the hinterland. Minas Tirith is situated in the south-east of Anórien on the Hill of Guard – the "out-thrust knee" of Mount Mindolluin, connected to the main mass of the mountain by a narrow \'shoulder\'. It faces eastward towards Osgiliath, over the Pelennor Fields surrounding the city, fertile town-lands stretching from the walls of the city proper to the Rammas Echor.\\nThe city is built on the hill with seven concentric tiers cut on the hill culminating in the Citadel at the summit. The outer wall is called Othram and is of the same material used in Orthanc. Each of the seven levels stands 100 feet higher than the one below it and is surrounded by a white wall.\\n\\nTerrain:\\nAnórien - Grassland\\nPelennor Fields - Grassland',
		desc_short = 'The Pelennor Fields',
	},
	["green_book_anfalas"] = {
		name = 'Anfalas',
		desc = "Anfalas, Sindarin for 'By the Shore', is a coastal region between the rivers Lefnui and Morthond, south of Pinnath Gelin. It is a land of fishermen and helps to supply the vast nation of Gondor with freshly caught fish. Due to its distance from any major  and its stores of wealth, Anfalas is often a target for the corsairs of Umbar and is raided frequently. The Men of Gondor believe that it was once inhabited by Elves. The only notable settlement of Anfalas is the Green Haven or Lond Galen.\\n\\nTerrain:\\nAnfalas - Grassland",
		desc_short = 'Anfalas',
	},
	["green_book_lossarnach"] = {
		name = 'Lossarnach',
		desc = 'Known as the "Vale of flowers", Lossarnach is a fertile region lying south of the eastern end of the White Mountains, the fertility of the region has given rise to Lossarnach being the breadbasket of Gondor with much of its produce being shipped to all corners of the coastal nation. It is also the region closest to Minas Tirith. Despite its importance domestically, Lossarnach is most famous for the sturdy and gruff axemen that make up the regions military. Performing key roles in the armies of Gondor, the axemen of Lossarnach are well known to the enemies of Gondor. Lossarnach is also the birthplace of the wise-woman Ioreth who served in the Houses of Healing of Minas Tirith, and Morwen Steelsheen, wife of King Thengel of Rohan.\\n\\nTerrain:\\nLossarnach - Forest',
		desc_short = 'Lossarnach',
	},
	["green_book_belfalas"] = {
		name = 'Belfalas',
		desc = 'Belfalas, Sindarin for \'Great Shore\', forms a part of Dor-en-Ernil, or the "Prince\'s land". The Prince in question here is the Lord of Dol Amroth, who lives at the city bearing his name. The first Lord of Dol Amroth was Galador, son of Imrazôr the Númenórean. Imrazôr was the son of Adrahil I, who was already known as the Prince, and lived in Belfalas. At some point Imrazôr moved to the area where the Elven haven of Edhellond is. According to tradition, there he married Mithrellas, a Silvan Elf of Lórien who had accompanied Nimrodel, the beloved of Lórien\'s king Amroth, on her journey towards Edhellond, but had become lost along with her mistress. Therefore Galador and his descendants had claim to Elven blood. After Imrazôr\'s death, Galador went on to found the city and later the princedom of Dol Amroth. He is counted as its first Lord. The specific date of its foundation is nowhere recounted. The large bay, stretching from Andrast in the west to the smaller bay of Umbar in the east, is named after the Belfalas peninsula.\\n\\nTerrain:\\nDor-en-Ernil - Mountainous\\nCape of Belfalas - Forest\\nRiverlands - Grassland\\nElf-haven - Grassland',
		desc_short = 'Belfalas',
	},
	["green_book_lebennin"] = {
		name = 'Lebennin',
		desc = "Lebennin, Sindarin for 'five waters', is a region and fiefdom in southern Gondor. Known as Fair Lebennin of the Five Streams, referring to the five separate rivers that run through the region. The largest city in the region is Pelargir but it is also home to Fanuilond, Brethil and many smaller villages. Lebennin is largely populated by men of mixed blood, as many of the inhabitants trace their ancestry to the forgotten 'Men of the Mountains' that had been displaced from the White Mountains by the Númenóreans. As Gondorian regions go, Lebennin is one of the most tumultuous and it has seen many battles and raids from the Haradrim and Corsairs. However perhaps the most notable skirmish to have occurred here was the siege of Pelargir by the faithful Gondorians in the kin-strife of T.A. 1432. Their enemy, Castamir the Usurper fled the city by boat and the siege was broken. The crossings of the Anduin are a constant battleground with the evil of the south.\\n\\nTerrain:\\nLebennin - Grassland\\nNorthern Lebennin - Forest\\nEastern Lebennin - Grassland",
		desc_short = 'Lebennin',
	},
	["green_book_lamedon"] = {
		name = 'Lamedon',
		desc = "Lamedon is a region and fiefdom in south-central Gondor and holds the accolade of being the most densely populated region outside of Anorien and Minas Tirith (this is not a verified fact). The meaning of Lamedon's name is lost to time but it is thought to be of pre-Númenórean origin.\\n\\nTerrain:\\nLamedon - Grassland",
		desc_short = 'Lamedon',
	},
	["green_book_ethring"] = {
		name = 'Ringló Vale',
		desc = "The Ringló Vale is a geographical feature of western Lamedon and comprises of only the river Ringló and its immediate surroundings. The region bares a lot of traffic from east and west as it houses the bridge city of Ethring, a major crossing point of the river Ringló and the main passage through the Gondorian heartlands. The city of Ethring started out as a group of merchant stalls, hastily built upon the large stone bridge. They would offer all sorts of wares to the vast numbers of people that used the bridge. Eventually they grew in wealth and began setting up taverns and smithies and operating as a key checkpoint for the east-west road. Once their wealth had become wide spread knowledge, the 'Merchants Bridge' became the target of many raids and Minas Tirith sent troops to defend the bridge. The garrison quickly erected walls, attracting scared villagers from the surrounding hamlets and villages and thus the town, as she was known in the War of the Ring, was born.\\n\\nTerrain:\\nRingló Vale - Forest",
		desc_short = 'Ringló Vale',
	},
	["green_book_Ithilien"] = {
		name = 'Ithilien',
		desc = 'Ithilien is a region and fiefdom of Gondor. It is the only part of Gondor on the eastern side of the Anduin, wedged in between the river and the Ephel Dúath. Ithilien was a fair and prosperous land during the Second Age and the first part of the Third Age, when Gondor was strong and Mordor deserted. Of old its chief city was Minas Ithil, the Tower of the Moon, but when this was captured by Mordor it was renamed Minas Morgul, the Tower of Black Sorcery. After this event, the majority of the people of Ithilien fled across the Anduin to escape war, but the Stewards of Gondor still kept scouts there, operating out of secret locations such as Henneth Annûn.\\n\\nTerrain:\\nLands of the Poros - Barren\\nIthilien - Forest',
		desc_short = 'Ithilien',
	},
	["green_book_Harondor"] = {
		name = 'Harondor',
		desc = "South Gondor, known in Sindarin as Harondor, is a disputed region between the rivers Poros and Harnen. Historically this region was a part of Gondor, but frequent assaults and invasions by the Corsairs of Umbar and the Haradrim meant that, by the later years of the Third Age, Gondor's rule over this region was limited.\\n\\nTerrain:\\nEastern Harondor - Barren\\nEmyn Harnen - Barren\\nWestern Harondor - Barren\\nHarondor - Barren\\nStraits of the Anduin - Barren",
		desc_short = 'Harondor',
	},
	["green_book_Morthond"] = {
		name = 'Morthond',
		desc = 'The Morthond or "Blackroot" is one of the seven rivers of Gondor and its swift course marks the divide between east and west Gondor. It rises near to the southern entrance of the paths of the dead and joins with the Ringló in the south to pass by the Elf-haven of Edhellond. The valley around the river is known for its harsh and steep terrain. Few Gondorians call this place home and those that do live out a rough existence hunting and foraging in the vale.\\n\\nTerrain:\\nMorthond Vale - Forest',
		desc_short = 'Morthond',
	},
	["green_book_Mirlond"] = {
		name = 'Principality of Mírlond',
		desc = 'Gobel Mírlond is an ancient city in south-western Harondor, founded by Númenóreans in the middle of the Second Age. For a long time, it was part of the important trade route between Pelargir and Umbar and the lands to the south. After the Kin-strife of Gondor, the city came under the rule of the Corsairs of Umbar, but this was hotly contested by the descendants of Eldacar. A peace was eventually agreed and the city now holds the accolade of being the only mixed allegiance city in Middle-earth. This unique identity has flourished in the late Third Age and the city has managed to weather the storm of constant warfare between Gondor and Umbar. In 2910 of the Third Age, a young lord of the city rose to power and declared the city a principality. It is now the largest settlement on the coast of the Bay of Belfalas between Linhir and Umbar, and as such, holds sway over a significant rural hinterland.\\n\\nTerrain:\\nPrincipality of Mírlond - Barren\\nMírlond Gap - Barren',
		desc_short = 'Principality of Mírlond',
	},
	["green_book_Dagorlad"] = {
		name = 'Dagorlad',
		desc = 'Dagorlad is a dusty plain that lay to the north-west of Mordor, immediately above the Black Gate of the Mordor. The Last Alliance fought here ferociously as they gained entry to Mordor but they lost many.\\n\\nTerrain:\\nDagorlad - Barren',
		desc_short = 'Dagorlad',
	},
	["green_book_Fangorn"] = {
		name = 'Fangorn',
		desc = "Fangorn Forest is a deep, dark woodland that grew beneath the southern Misty Mountains, under the eastern flanks of that range. It gained notoriety as the habitat of the Ents in the Third Age. The forest, known as Entwood in Rohan, was named after the oldest Ent, Fangorn.\\nFangorn forest is the easternmost survivor of the immense forest that spanned all of Eriador and Calenardhon in the First Age and early Second Age, but which was destroyed by the Númenóreans and Sauron. Fangorn forest is the oldest part of Treebeard's realm, and here the Ents retreated. Settlement within the forest is almost impossible and only a handful of hardy hunters can exist here.\\n\\nTerrain:\\nFangorn Forest - Forest",
		desc_short = 'Fangorn',
	},
	["green_book_Tolfalas"] = {
		name = 'Tolfalas',
		desc = 'Tolfalas is a large island, also named in the form Tol Falas, that stands beyond the Ethir Anduin in the Bay of Belfalas. During the Drowning of Númenor, Tolfalas was almost destroyed and was left like a barren and lonely mountain in the water not far from the Ethir. Its sharp southern cape is traditionally considered as marking the southernmost point of Gondor proper. The island is rough and unforgiving and the Gondorians have only been able to establish a town on the eastern coast.\\n\\nTerrain:\\nIsle of Tolfalas - Barren',
		desc_short = 'Tolfalas',
	},
	["green_book_Andrast"] = {
		name = 'Andrast',
		desc = 'Andrast is a long cape in the south-west of Gondor.\\nThe cape is nominally part of Gondor, but it is not populated by the Númenóreans. At the end of the Third Age, the area is still populated by tribes of the Drúedain and other hostile men.\\nThe White Mountains end their southward bend at the Andrast, and as such it forms an effective barrier to invaders from the north for Gondor. There are no passes over it, so all have to venture around the Ras Morthil.\\n\\nTerrain:\\nAndrast - Barren\\nRas Morthil - Mountainous',
		desc_short = 'Andrast',
	},
	["green_book_celebrant"] = {
		name = 'Celebrant',
		desc = 'The field of Celebrant lies to the south of Lothlórien and was the site, in ages past of a great battle between Gondor, Rhûn and the coming Éothéod. Its northern border is marked by the Anduin river and its southern, the Limlight.\\n\\nTerrain:\\nLimlight Fields - Forest\\nFields of Celebrant - Grassland',
		desc_short = 'Celebrant',
	},
	["green_book_gundabad"] = {
		name = 'Mount Gundabad',
		desc = "Mount Gundabad was a mountain adjacent to the northern reaches of the Misty Mountains, made up ofthree conjoined peaks. Bordering Forodwaith to the north, the mountain undoubtedly has a cold climate. According to the Dwarves, Durin the Deathless, eldest of the Fathers of the Dwarves, awoke at Mount Gundabad shortly after the Awakening of the Elves. From that time forward, the mountain was revered by the Dwarves. However, since Durin awoke alone he did not stay at the mountain; he walked southward until he founded Khazad-dûm. In the early ages, Mount Gundabad did serve as a place of assembly for delegations of Dwarves, but after the S.A. 1679, was sacked by orcs under Sauron's command during the War of Elves and Sauron, and the mountain became the Orcs' capital in the north.\\nMountains of Gundabad - Mountainous",
		desc_short = 'Mount Gundabad',
	},
	["green_book_guldur"] = {
		name = 'Dol Guldur',
		desc = 'Dol Guldur ("Hill of Sorcery"),also called "the dungeons of the Necromancer",is a stronghold of Sauron located in the south of Mirkwood. Originally known as Amon Lanc ("Bald Hill"), it had been the capital of Oropher\'s Silvan Elves, who had departed north to the Dark Mountains. Somewhere after T.A. 1000, an evil presence took over Amon Lanc. It was in 1050 that a shadow fell upon Greenwood and it began to be called Mirkwood. The hostile entity was known as "the Necromancer" by the peoples. Despite fleeing from Dol Guldur in shortly before the Battle of the Five Armies after an assault by the White Council, Sauron has once again commanded the Hill of Sorcerery to be fortified, and it stands to menance the Free Peoples once more.\\nNaked Hill - Barren',
		desc_short = 'Dol Guldur',
	},
	["green_book_moria"] = {
		name = 'Moria',
		desc = "Khazad-dûm, latterly known as Moria (The Black Chasm, The Black Pit), was the grandest and most famous of the mansions of the Dwarves. There, for many thousands of years, a thriving Dwarvish community created the greatest city ever known. It lies in the central parts of the Misty Mountains, tunnelled and carved through the living rock of the mountains themselves. By the Second Age a traveller could pass through it from the west of the range to the east. Founded in very ancient days by Durin who awoke at Mount Gundabad in the Misty Mountains, he came upon the valley Azanulbizar beneath the mountains and looked into a shimmering lake and saw a crown of stars reflected in its waters. He named that lake Kheled-zâram, the Mirrormere and it remais a revered place among Dwarves of all houses, and the Durin's Stone was erected on the location of that event. Most of its great wealth was based on the rare Mithril that was found in its mines, and as the centuries passed, the Dwarves mined deeper and deeper for the precious metal. In the year T.A. 1980, their deep digging unleashed a nameless terror, a Balrog from the Elder Days, that wreaked dreadful destruction. In slaying the King, Durin VI, the Balrog became known as Durin's Bane, and the Dwarves fled their ancient home, leaving it to the Balrog and the goblins of the Misty Mountains.\\nEastern Peaks - Mountainous\\nWestern Peaks - Mountainous",
		desc_short = 'Moria',
	},
    ["green_book_Ered_Luin"] = {
		name = "Ered Luin",
		desc = "The Blue Mountains, also known as the Ered Lindon, is the mountain range at the far west of Eriador.\nThe Mountains were ruined during the War of Wrath, and in the south central end of the range the sea broke through.\nMost of the Dwarves migrated east to Khazad-dûm, however some remained to rebuild. Overtime however, the Dwarves seemed to have largely moved to the Southern chain.\nIn the Third Age the Blue Mountains apparently saw the return of many of the Firebeards and Broadbeams due to the isolation/stagnation of Khazad Dûm. It also became the new home for many of Durin's folk who were exiled from their halls in Erebor by Smaug the Dragon.\n\nTerrain:\nEred Luin Proper - Mountainous\nNorthern Ered Luin - Mountainous\nSouthern Ered Luin - Mountainous\nEred Luin Foothills - Forest",
		desc_short = "Ered Luin",
	},
	["green_book_Withered_Heath"] = {
		name = "Withered Heath",
		desc = "The Withered Heath is a long narrow valley set in the eastern part of the Grey Mountains, where the mighty range forks in two. The land is famous, for it is the breeding ground of dragons and it is from this heath that Smaug the Golden set out to devour all in his path en route to Erebor. Additionally, Scatha the Great Worm came down from the Withered Heath before terrorizing the upper Anduin vales and finally being slain by Fram, leading to the renaming of 'Framsburg'. Smaug was the last of the great dragons but many minor worms and drakes still live in the burnt lands of the heath.\n\nTerrain:\nWithered Heath - Mountainous",
		desc_short = "Withered Heath",
	},
	["green_book_pukel_lands"] = {
		name = "Drúwaith Iaur",
		desc = "Drúwaith Iaur or Old Púkel land is a region on the west of Gondor. Drúwaith Iaur is not a part of the realm of Gondor, and therefore also was not of the Reunited Kingdom. It is home to the remnants of the Drúedain, the original inhabitants of the Ered Nimrais, who were dispersed by the Númenóreans as they were hostile to them. The northern part of Drúwaith Iaur is also home to the Dunlendings, who fear the Drûg because they use poisoned arrows.\n\nTerrain:\nParth Iaur - Grassland\nDrúwaith Iaur - Barren\nNan-i-Faugeh - Mountainous",
		desc_short = "Drúwaith Iaur",
	},
	["green_book_misty_mountains"] = {
		name = "Misty Mountains",
		desc = "The Misty Mountains or Mountains of Mist is a great mountain range that lies between Eriador in the west and the Great River Anduin in the east. They run 795 miles (1,280 kilometres) from Mount Gundabad in the far north to Methedras in the south. Some of the peaks are 12,000 feet high.The most important passes are the High Pass and the Redhorn Pass. There is also a pass at the source of the Gladden River.\n\nTerrain:\nScatha's Gap - Mountainous\nHigh Pass - Mountainous\nKala Gorge - Mountainous",
		desc_short = "Misty Mountains",
	},
	["green_book_Iron_Hills"] = {
		name = "Iron Hills",
		desc = "The Iron Hills are a range of hills in the northeast of the known parts of Middle-earth, bordering Rhûn. The Hills were mined for thousands of years by the Dwarves, being their main supply of iron. The Dwarf road through Mirkwood runs northeast to the Hills for the Dwarf traders that went to and from Khazad-dûm.\n\nTerrain:\nIron Hills - Mountainous",
		desc_short = "Iron Hills",
	},
	["green_book_anduin_vale"] = {
		name = "Anduin Vale",
		desc = "Anduin is the river that crossed most of Middle-earth east of the Misty Mountains. Passing through many lands, it had received many names - Langflood by the ancestors of the Rohirrim, the Great River of Wilderland in the Westron of Rivendell and the Shire, and simply the Great River in Gondor. All these names are in recognition of the river's length. It flows from its source in the Grey and Misty Mountains to the Ethir Anduin in the Great Sea (Belegaer).\n\nTerrain:\nUpper Vales - Grassland\nGreylin Vales - Grassland\nBeorn's Woods - Forest\nAnduin Valley - Grassland\nMiddle Vales - Forest\nLower Vales - Forest\nLower Gladden - Grassland\nBoughs of Mirkwood - Grassland",
		desc_short = "Anduin Vale",
	},
	["green_book_weather_hills"] = {
		name = "Weather Hills",
		desc = "The Weather Hills refers to the north-south range of hills that lies in central Eriador, and in ancient times marked part of the border between the lands of Arthedain and Rhudaur. Weathertop, or Amon Sûl, lies at the southern end of the range. When Angmar was formed and Rhudaur became hostile to Arthedain, Argeleb I fortified the range but was later slain there by men of Rhudaur.\n\nTerrain:\nWeather Hills - Mountainous",
		desc_short = "Weather Hills",
	},
	["green_book_eryn_vorn"] = {
		name = "Eryn Vorn",
		desc = "The cape of Emyn Vorn is a densely wooded region, teeming with wildlife. It is one of the last remnants of the massive forest that spanned all of central Middle-earth before the latter Second Age. The deforestation of the region was due to the Númenóreans needing wood dearly as they began to chart the seas and construct more permanent residences upon Middle-earth. The Woodsmen of this region are of the same blood as the clansmen of Enedwaith, having migrated to the cape in the early Third Age.\n\nTerrain:\nEryn Vorn - Forest",
		desc_short = "Eryn Vorn",
	},
}


function addWatchtowers(faction)
    if faction.settlementsNum > 0 then
        for x = 0, faction.settlementsNum -1 do
            local settlement = faction:getSettlement(x)
            if settlement:buildingPresentMinLevel("roads", false) then
                if not towers_already[settlement.localizedName] then
                    if checkTileEmpty(settlement.xCoord, settlement.yCoord-10) then
                        local too_close = false
                        local region = M2TW.stratMap.getRegion(settlement.regionID);
                        for i = 0, region.watchtowerCount - 1 do
                            if region.watchtowerCount > 0 then
                                local thisTower = region:getWatchtower(i)
                                if checkStratRange(thisTower.xCoord, thisTower.yCoord, settlement.xCoord, settlement.yCoord-10, 5) then
                                    too_close = true
                                end
                            end
                        end
                        if not too_close then
                            --print("adding tower")
                            faction:createWatchtower(settlement.xCoord, settlement.yCoord-10)
                        end
                    end
                    if checkTileEmpty(settlement.xCoord-10, settlement.yCoord) then
                        local too_close = false
                        local region = M2TW.stratMap.getRegion(settlement.regionID);
                        for i = 0, region.watchtowerCount - 1 do
                            if region.watchtowerCount > 0 then
                                local thisTower = region:getWatchtower(i)
                                if checkStratRange(thisTower.xCoord, thisTower.yCoord, settlement.xCoord-10, settlement.yCoord, 5) then
                                    too_close = true
                                end
                            end
                        end
                        if not too_close then
                            --print("adding tower")
                            faction:createWatchtower(settlement.xCoord-10, settlement.yCoord)
                        end
                    end
                    if checkTileEmpty(settlement.xCoord+10, settlement.yCoord) then
                        local too_close = false
                        local region = M2TW.stratMap.getRegion(settlement.regionID);
                        for i = 0, region.watchtowerCount - 1 do
                            if region.watchtowerCount > 0 then
                                local thisTower = region:getWatchtower(i)
                                if checkStratRange(thisTower.xCoord, thisTower.yCoord, settlement.xCoord+10, settlement.yCoord, 5) then
                                    too_close = true
                                end
                            end
                        end
                        if not too_close then
                            --print("adding tower")
                            faction:createWatchtower(settlement.xCoord+10, settlement.yCoord)
                        end
                    end
                    if checkTileEmpty(settlement.xCoord, settlement.yCoord+10) then
                        local too_close = false
                        local region = M2TW.stratMap.getRegion(settlement.regionID);
                        for i = 0, region.watchtowerCount - 1 do
                            if region.watchtowerCount > 0 then
                                local thisTower = region:getWatchtower(i)
                                if checkStratRange(thisTower.xCoord, thisTower.yCoord, settlement.xCoord, settlement.yCoord+10, 5) then
                                    too_close = true
                                end
                            end
                        end
                        if not too_close then
                            --print("adding tower")
                            faction:createWatchtower(settlement.xCoord, settlement.yCoord+10)
                        end
                    end
                    towers_already[settlement.localizedName] = true
                end
            end
        end
    end
end

function addEURSetts()

    for k, v in pairs(new_EUR_setts) do
            if v ~= nil then
                if checkTileEmpty(v.x, v.y) then
                    --local tile = M2TW.stratMap.getTile(v.x, v.y)
                    --print("Adding sett:", v.x, v.y)
                    local faction = nil
                    if v.expandAI == eur_player_faction.name then
                        if not setts_player_expansion then
                            faction = eur_campaign:getFaction(v.faction)
                        else
                            faction = eur_campaign:getFaction(v.expandAI)
                        end
                    else
                        if v.faction == v.expandAI then
                            faction = eur_campaign:getFaction(v.faction)
                        else
                            faction = eur_campaign:getFaction(v.expandAI)
                        end
                    end
                    if faction ~= nil then
                        local sett = faction:addSettlement(v.x, v.y, "eursett_"..tostring(k), v.level, v.castle)
                        if sett ~= nil then
                            --[[if sett.name == "eursett_9" then
                                sett.rebelEntry = eur_sMap:getSettlement("Enedwaith").rebelEntry
                                local army = stratmap.game.createArmyInSettlement(sett)
                                for i = 0, 3 do
                                    army:createUnit("Goblin Band", 1, 0, 0)
                                end
                            end]]
                            local fact_id = eur_campaign:getFaction(v.culture).factionID
                            sett.creatorFactionID = fact_id
                            sett.subFactionID = fact_id
                            sett.localizedName = v.name
                            sett:createBuilding("minor_sett")
                            local army = stratmap.game.createArmyInSettlement(sett)
                            for i = 1, #v.units do
                                army:createUnit(v.units[i], 1, 0, 0)
                            end
                            for i = 1, #v.bu do
                                local bu = sett:createBuilding(v.bu[i]);
                                if bu ~= nil then
                                    if bu_culture_swap[v.bu] then
                                        bu.factionID = eur_campaign:getFaction(bu_culture_swap[v.bu]).factionID
                                    end
                                end
                            end
                            sett.settlementStats.population = v.population
                            --sett.isMinorSettlement = false
                            sett.baseFertility = 1
                            --sett.name = v.name
                            if strat_cas_setts[sett.name] then
                                setCasSett(sett)
                            end
                            v = nil
                        else
                            print("Adding sett failed: "..v.name, v.x, v.y)
                        end
                    else
                        print(v.faction, v.expandAI, "not found")
                    end
                else
                    print("Adding sett failed: Tile invalid"..v.name, v.x, v.y)
                end
            end
    end
end

setts_divisible = 1
added_already = false

function addSetts()
    if cutdown_setts then
        new_setts = cutdown_new_setts
    end
    local index = 1
    if added_already then return end
    for k, v in pairs(new_setts) do
        if (index % setts_divisible == 0) then
            if v ~= nil then
                if checkTileEmpty(v.x, v.y) then
                    --local tile = M2TW.stratMap.getTile(v.x, v.y)
                    --print("Adding sett:", v.x, v.y)
                    local faction = nil
                    if eur_player_faction.name == "russia" then
                        if v.faction == "russia" then
                            faction = eur_campaign:getFaction("slave")
                        elseif v.expandAI == "russia" then
                            faction = eur_campaign:getFaction("slave")
                        else
                            if v.expandAI == eur_player_faction.name then
                                if not setts_player_expansion then
                                    faction = eur_campaign:getFaction(v.faction)
                                else
                                    faction = eur_campaign:getFaction(v.expandAI)
                                end
                            else
                                if v.faction == v.expandAI then
                                    faction = eur_campaign:getFaction(v.faction)
                                else
                                    faction = eur_campaign:getFaction(v.expandAI)
                                end
                            end
                        end
                    else
                        if v.expandAI == eur_player_faction.name then
                            if not setts_player_expansion then
                                faction = eur_campaign:getFaction(v.faction)
                            else
                                faction = eur_campaign:getFaction(v.expandAI)
                            end
                        else
                            if v.faction == v.expandAI then
                                faction = eur_campaign:getFaction(v.faction)
                            else
                                faction = eur_campaign:getFaction(v.expandAI)
                            end
                        end
                    end
                    if faction ~= nil then
                        local sett = faction:addSettlement(v.x, v.y, "chrissett_"..tostring(k), v.level, v.castle)
                        if sett ~= nil then
                            sett.localizedName = v.name
                            sett:createBuilding("minor_sett")
                            if sett.ownerFaction.name == "slave" then
                                local army = stratmap.game.createArmyInSettlement(sett)
                                local region = eur_sMap.getRegion(sett.regionID);
                                local region_army = nil
                                if region.regionName ~= "the sea" then
                                --print("region: ", sett.regionID, region.regionID, v.name, v.x, v.y)
                                    local region_sett = region:getSettlement(0)
                                    if region_sett.ownerFaction.name == "slave" then
                                        sett.rebelEntry = region_sett.rebelEntry
                                        sett.army.rebelEntry = region_sett.rebelEntry
                                        if region_sett.army then
                                            region_army = region_sett.army
                                        end
                                    end
                                end
                                if region_army ~= nil then
                                    for i = 0, region_army.numOfUnits -1 do
                                        local unit = region_army:getUnit(i)
                                        if i > 2 and math.random(1, 100) > 50 then
                                            army:createUnit(unit.eduEntry.eduType, unit.exp, unit.armourLVL, unit.weaponLVL)
                                        else
                                            army:createUnit(unit.eduEntry.eduType, unit.exp, unit.armourLVL, unit.weaponLVL)
                                        end
                                    end
                                else
                                    army:createUnit("Sellswords", 2, 0, 0)
                                    army:createUnit("Bandits", 0, 0, 0)
                                    army:createUnit("Bandits", 0, 0, 0)
                                    if math.random(1, 100) < 30 then
                                        army:createUnit("Lumbermen", 0, 0, 0)
                                        army:createUnit("Lumbermen", 0, 0, 0)
                                        army:createUnit("Woodland Hunters", 0, 0, 0)
                                        army:createUnit("Woodland Hunters", 0, 0, 0)
                                    end
                                end
                            else
                                local army = stratmap.game.createArmyInSettlement(sett)
                                local rand1 = math.random(1, 3)
                                local rand2 = math.random(1, 3)
                                if unique_unit[v.name] then
                                    for i = 1, #unique_unit[v.name].unit do
                                        army:createUnit(unique_unit[v.name].unit[i][1], unique_unit[v.name].unit[i][2], 0, 0)
                                    end
                                else
                                    if SWAP_GARRISON[sett.ownerFaction.name] then
                                        army:createUnit(SWAP_GARRISON[sett.ownerFaction.name].new[rand1], 0, 0, 0)
                                        --army:createUnit(SWAP_GARRISON[sett.ownerFaction.name].new[rand2], 0, 0, 0)
                                    end
                                end
                            end
                            if v.castle then
                                if v.level == 0 then
                                    sett.settlementStats.population = (sett.settlementStats.population-math.random(50, 250))
                                else
                                    sett.settlementStats.population = (sett.settlementStats.population+math.random(100, 300))
                                end
                            else
                                if v.level == 0 then
                                    sett.settlementStats.population = (sett.settlementStats.population-math.random(150, 300))
                                else
                                    sett.settlementStats.population = (sett.settlementStats.population+math.random(50, 200))
                                end
                            end
                            --sett.isMinorSettlement = false
                            sett.baseFertility = 1
                            --sett.name = v.name
                            if strat_cas_setts[sett.name] then
                                setCasSett(sett)
                            end
                            v = nil
                        else
                            print("Adding sett failed: "..v.name, v.x, v.y)
                        end
                    else
                        print(v.faction, v.expandAI, "not found")
                    end
                else
                    print("Adding sett failed: Tile invalid"..v.name, v.x, v.y)
                end
            end
        end
        index = index + 1
    end
    --eur_sMap:getSettlement("chrissett_11"):createPort(81, 375,false);
end

