BOOK_FIXED = {}

function fixGreenDesc(levelname, newfacid)
    for x = 1, #GREEN_BOOK_BU do
        local bu = EDB.getBuildingByName(GREEN_BOOK_BU[x])
        for i = 0, bu.buildingLevelCount - 1 do
            local level = bu:getBuildingLevel(i)
            if level then
                if level.name == levelname then
                    if not BOOK_FIXED[levelname..tostring(newfacid)] then
                        if my_lua_table[levelname] then
                            local desc = my_lua_table[levelname].desc
                            local desc_short = my_lua_table[levelname].desc_short
                            local localname = my_lua_table[levelname].name
                            level:setLocalizedName(newfacid, localname)
                            level:setLocalizedDescr(newfacid, desc)
                            level:setLocalizedDescrShort(newfacid, desc_short)
                            BOOK_FIXED[levelname..tostring(newfacid)] = true
                        else
                            --print(levelname)
                        end
                    end
                end
            end
        end
    end
end

