            if temp_fort_char ~= M2TW.selectionInfo.selectedCharacter then
                temp_fort_char = M2TW.selectionInfo.selectedCharacter
            end
        end
    end
    if not temp_fort_char then return end
    ImGui.SetNextWindowPos(580*eurbackgroundWindowSizeRight, 400*eurbackgroundWindowSizeBottom)
