                        eurStyle("tooltip", false)
                    end
                    ImGui.SameLine()
                    ImGui.Image(fort_text_no.img, 300*eurbackgroundWindowSizeRight, 100*eurbackgroundWindowSizeBottom)
                end
            else
                --too many forts
                local upgrade_clicked = ImGui.ImageButton("buildfort_1",fort.img, 150*eurbackgroundWindowSizeRight, 100*eurbackgroundWindowSizeBottom)
